set -e
echo '=== configure redis ==='
cp -a /etc/redis.conf "/etc/redis.conf.bak.$(date +%Y%m%d_%H%M%S)"

# CentOS7 redis 3.2 conf tweaks via sed
sed -i 's/^bind .*/bind 127.0.0.1/' /etc/redis.conf
sed -i 's/^protected-mode .*/protected-mode yes/' /etc/redis.conf
sed -i 's/^port .*/port 6379/' /etc/redis.conf
sed -i 's/^tcp-keepalive .*/tcp-keepalive 60/' /etc/redis.conf
sed -i 's/^# maxmemory <bytes>/maxmemory 512mb/' /etc/redis.conf
sed -i 's/^maxmemory .*/maxmemory 512mb/' /etc/redis.conf
# policy line is commented by default
if grep -q '^maxmemory-policy ' /etc/redis.conf; then
  sed -i 's/^maxmemory-policy .*/maxmemory-policy allkeys-lru/' /etc/redis.conf
else
  sed -i 's/^# maxmemory-policy .*/maxmemory-policy allkeys-lru/' /etc/redis.conf
fi
# if still missing, append
grep -q '^maxmemory ' /etc/redis.conf || echo 'maxmemory 512mb' >> /etc/redis.conf
grep -q '^maxmemory-policy ' /etc/redis.conf || echo 'maxmemory-policy allkeys-lru' >> /etc/redis.conf

grep -E '^(bind|port|protected-mode|maxmemory|maxmemory-policy|tcp-keepalive)' /etc/redis.conf

echo '=== enable & start redis ==='
systemctl enable redis
systemctl restart redis
systemctl is-active redis
redis-cli ping
redis-cli INFO server | head -12
redis-cli CONFIG GET maxmemory
redis-cli CONFIG GET maxmemory-policy

echo '=== php redis module ==='
ls -la /etc/php.d/*redis* /usr/lib64/php/modules/redis.so
cat /etc/php.d/*redis*.ini
systemctl restart php-fpm
# also httpd uses proxy_fcgi to same php-fpm
php -m | grep -i redis
php -r '$r=new Redis(); $r->connect("127.0.0.1",6379); $r->set("crm_probe","ok",30); echo "php_redis=".$r->get("crm_probe")."\n"; echo "ext=".phpversion("redis")."\n";'

echo '=== bitrix cache smoke test ==='
php <<'PHP'
$_SERVER["DOCUMENT_ROOT"]="/var/www/html";
$_SERVER["SERVER_NAME"]="192.168.2.104";
define("NO_KEEP_STATISTIC", true);
define("NOT_CHECK_PERMISSIONS", true);
require "/var/www/html/bitrix/modules/main/include/prolog_before.php";

$cache = \Bitrix\Main\Data\Cache::createInstance();
$key = 'agent_redis_test_'.time();
$miss = !$cache->initCache(120, $key, '/agent');
echo "first_init miss_expected=".($miss?'YES':'NO')."\n";
if ($cache->startDataCache()) {
  $cache->endDataCache(['hello'=>'redis', 'ts'=>time()]);
  echo "wrote\n";
}
$cache2 = \Bitrix\Main\Data\Cache::createInstance();
$hit = $cache2->initCache(120, $key, '/agent');
echo "second_init hit=".($hit?'YES':'NO')."\n";
if ($hit) { print_r($cache2->getVars()); }

$r = new Redis();
$r->connect('127.0.0.1', 6379);
$keys = $r->keys('*');
echo "redis_keys_count=".count($keys)."\n";
echo "sample=".json_encode(array_slice($keys,0,5))."\n";
echo "dbsize=".$r->dbSize()."\n";
PHP

echo '=== DONE ==='
